package com.establo.controller;import com.establo.dto.ReservationDto;import com.establo.service.ReservationService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.data.web.PageableDefault;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;import java.util.List;
@RestController @RequestMapping("/api/reservations") @RequiredArgsConstructor public class ReservationController {private final ReservationService s;@GetMapping List<ReservationDto> all(){return s.all();}@GetMapping("/search") Page<ReservationDto> search(@RequestParam(required=false)String q,@RequestParam(required=false)String type,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate date,@PageableDefault(size=20,sort="startAt")Pageable pageable){return s.search(q,type,date,pageable);}@PostMapping ResponseEntity<ReservationDto> create(@Valid @RequestBody ReservationDto d){return ResponseEntity.status(201).body(s.create(d));}@PutMapping("/{id}") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") ReservationDto update(@PathVariable Long id,@Valid @RequestBody ReservationDto d){return s.update(id,d);}@PatchMapping("/{id}/cancel") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") @ResponseStatus(HttpStatus.NO_CONTENT) void cancel(@PathVariable Long id){s.cancel(id);}}
